#include <vector>
#include <algorithm>
#include <unordered_map>

using namespace std;

class UnionFind {
private:
    vector<int> parent;
    vector<int> rank;
    int components;

public:
    UnionFind(int n) : components(n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
            components--;
        }
    }

    int getComponents() const {
        return components;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (k <= 1) return 0;
    if (k > n) return -1; // Impossible case as per problem constraints, but handle it if needed

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    long long left = 0;
    long long right = 1e18;
    long long answer = 0;

    // Check if initial components already >= k
    if (uf.getComponents() >= k) {
        return 0;
    }

    // Binary search for the minimal t
    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind tempUF(n);
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                tempUF.unite(edge[0], edge[1]);
            }
        }
        if (tempUF.getComponents() >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

